import json, os, sys

def load_comm(layer, book):
    path = f'data/commentary/mkt-{layer}/{book}.json'
    if os.path.exists(path):
        with open(path) as f:
            return json.load(f)
    return {}

def save_comm(layer, book, data):
    path = f'data/commentary/mkt-{layer}/{book}.json'
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f'wrote {path}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, text in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = text

SAMUEL = {
    "17": {
        "1": "<p><em>wayyiqbəṣû pəlištîm ʾeṯ-maḥănêhem lammiḥlāmāh</em> — 'gathered their camps/forces for battle.' The term <em>maḥăneh</em> (camp, army) is both the military encampment and the assembled force within it; the MKT 'forces' captures the military sense. Socoh (Khirbet Abbad, c.21km WSW of Bethlehem) is in the Shephelah foothills — the contested buffer zone between Philistia and Judah. The Philistines are staging in Israelite territory, forcing Israel to respond defensively.</p>",
        "2": "<p><em>ʾēmeq hāʾēlāh</em> — 'Valley of the Terebinth' (MKT: 'Valley of Elah'). The name derives from the <em>ʾēlāh</em> tree (terebinth or oak). The site is identified with Wadi es-Sant, where a dry streambed provided the smooth stones David would select (v40). The two armies deploy on opposite hills with the valley between — a standard ANE tactical standoff waiting for an individual champion or breakthrough.</p>",
        "3": "<p>The spatial geometry — Philistines on one hill, Israel on another, <em>haggayʾ bênêhem</em> ('the valley between them') — establishes the impasse that Goliath's challenge is designed to break. In ANE warfare, champion combat was an accepted device for avoiding mass casualties; the text presents this as a genuine Philistine proposal, not mere bravado. The valley functions as a no-man's-land until David crosses it (v48).</p>",
        "5": "<p><em>qoḇaʿ nəḥōšeṯ ʿal-rōʾšô wəširiôn qaśqaśîm hûʾ lāḇûš</em> — bronze helmet and scale armor. The <em>širiôn qaśqaśîm</em> ('coat of scale armor,' lit. 'armor of scales') is the laminar bronze plate-suit documented in ANE archaeology and known from Ugaritic and Egyptian texts; the 5,000-shekel weight (~57kg) is plausible for full body-armor. The catalogue of Goliath's equipment (vv5–7) follows the literary convention of ekphrasis — detailed description establishing the champion's invincibility before the reversal.</p>",
        "6": "<p><em>kîdôn nəḥōšeṯ bên kētēpāyw</em> — 'a javelin of bronze between his shoulders.' The term <em>kîdôn</em> appears elsewhere as a short lance or dart (Josh 8:18; Job 39:23); its placement 'between his shoulders' (slung on the back) indicates a third projectile weapon in addition to the spear and sword. Goliath is equipped for every combat range: javelin for distance, spear for mid-range, sword for close combat. The asymmetry with David's sling (v40) is the narrative's central irony.</p>",
        "7": "<p><em>wəḥēṣ ḥaniṯô kəmənôr ʾōrəgîm</em> — 'the shaft of his spear was like a weaver's beam.' The comparison to a weaver's beam (the horizontal roller on a loom, typically 5–7cm thick) communicates mass rather than size. The iron point weighing 600 shekels (~6.8kg) represents high-grade iron weaponry; the Philistines had metallurgical superiority in iron at this period (1 Sam 13:19–22). The shield-bearer walking ahead completes the picture of a fully-serviced war machine.</p>",
        "8": "<p><em>ʿibrîm ʾattem ʿăḇādîm ləšāʾûl</em> — 'you are Hebrews, servants of Saul.' Goliath's use of <em>ʿibrîm</em> ('Hebrews') rather than 'Israel' is the outsider's ethnic label, associated in Samuel with Philistine usage and carrying social-inferior connotations (cf. 1 Sam 4:6, 9; 13:3, 7, 19). The legal framework of the challenge — loser's side becomes servants (<em>ʿăḇādîm</em>) of the winner — formalises the combat as a binding covenant-substitution.</p>",
        "9": "<p>The conditional structure of the challenge — 'if he can kill me, we serve you; if I kill him, you serve us' — is legally precise. The verb <em>wə<sup>ʿ</sup>ăḇaḏtem ʾōṯānû</em> ('you shall serve us') carries the full weight of tributary servitude. The Philistine champions's challenge inverts the covenant structure: Israel's God should give them victory; instead they must produce a man who can match Goliath. The narrative will resolve by collapsing the human champion structure through YHWH's intervention via David.</p>",
        "10": "<p><em>ḥēraptî ʾeṯ-maʿarəḵôṯ yiśrāʾēl</em> — 'I have defied/taunted the battle lines of Israel.' The verb <em>ḥārap</em> (Piel: to taunt, revile, reproach) recurs as the chapter's theological key: Goliath is not merely challenging individual combat but insulting <em>maʿarəḵôṯ ʾĕlōhîm ḥayyîm</em> (v26, 'the battle lines of the living God'). David will reframe Goliath's challenge as an insult against YHWH personally (vv45–46), transforming individual combat into a theological contest.</p>",
        "11": "<p><em>wayyišməʿ šāʾûl wəkol-yiśrāʾēl ʾeṯ-dib·rê happəlištî hāʾēlleh wayyēḥattû wayyirəʾû məʾōḏ</em> — they were 'dismayed' (<em>ḥāṯaṯ</em>) and 'greatly afraid.' <em>ḥāṯaṯ</em> is the technical term for the psychological collapse of military courage (Deut 1:21; Josh 1:9; Isa 8:9); it is the fear that undoes battle readiness. Saul himself, anointed king to lead Israel's armies (1 Sam 8:20), is paralysed alongside his troops — an indictment of the existing leadership framework.</p>",
        "12": "<p>The narrator introduces David's genealogy at the moment of Israel's crisis — a narrative device signalling that the solution to the impasse has already been prepared. <em>ʾepraṯî mibbêṯ leḥem yəhûḏāh</em> ('an Ephrathite from Bethlehem of Judah') is the full ethnic-geographical identification; <em>ʾepraṯî</em> designates the Bethlehemite clan (Ruth 1:2; Mic 5:2). Jesse's advanced age and eight sons establishes the family context that will make David's appearance at the front unexpected.</p>",
        "13": "<p>The three eldest sons — Eliab, Abinadab, Shammah — are named and identified with Saul's army. Their presence at the front and David's absence sets up the contrast: David is not a soldier but a shepherd, which is precisely the background that qualifies him for what follows (v34). The naming of the three eldest also establishes Eliab as the eldest who had seemed to Samuel the obvious choice (16:6–7) but was rejected. His reappearance in v28 will show his character.</p>",
        "14": "<p><em>wədāwid hûʾ haqqāṭōn</em> — 'David was the youngest (<em>qāṭōn</em>).' The adjective <em>qāṭōn</em> (small, youngest, least significant) is precisely the category YHWH overturns in 1 Samuel's theology (16:7, 11; cf. 9:21 — Saul's own initial self-deprecation). The youngest son sent to provision his brothers recapitulates the Joseph pattern (Gen 37:13–14) and points toward the reversal the narrative is constructing.</p>",
        "15": "<p><em>wədāwid hōlēk wāšāb mēʿal šāʾûl</em> — 'David went back and forth from Saul to tend his father's flock.' The verb <em>hōlēk wāšāb</em> (going and returning) describes a commuter pattern; David has a dual role as court musician (16:18–23) and pastoral shepherd. This verse is sometimes cited in the textual discussion about the apparent narrative tension between ch16 and ch17; the MKT renders it naturally as a continuing pattern of alternating service.</p>",
        "16": "<p><em>wayyaškem happəlištî wayyaʿărōḇ baqqer ûḇāʿereḇ</em> — the Philistine 'rose early and presented himself morning and evening for forty days.' The twice-daily challenge ('morning and evening') mirrors the twice-daily tamid offering in the tabernacle (Ex 29:38–42) — a dark parody of liturgical regularity. Forty days is the standard biblical period of testing (Num 13:25; Jonah 3:4; Matt 4:2). The challenge has liturgical rhythm but no covenantal content.</p>",
        "17": "<p>Jesse's errand — <em>ʾēpāh qālûy ʾeśer leḥem</em> ('an ephah of roasted grain and ten loaves') — is a practical supply run, not a heroic mission. The provisions are standard field rations: roasted grain (<em>qālî</em>) was portable, shelf-stable army food (Ruth 2:14; 2 Sam 17:28). Ten cuts of cheese (<em>ḥaṣar ḥĕlāḇîm</em>) go to the unit commander — small gifts of honour. Jesse's errand positions David at the battle line without any military mandate, making his intervention entirely contingent.</p>",
        "18": "<p><em>wəʾeṯ-ʾaḥêkā tifqōḏ ləšālôm wəʾeṯ-ʿarūbbāṯām tiqkāḥ</em> — 'check on your brothers' welfare (<em>šālôm</em>) and bring back some token from them.' The word <em>ʿǎrubbāh</em> (pledge, token — given as security) is unusual here; some read it as 'word/news' (emending slightly). The MKT 'token' captures the sense of tangible evidence that David reached the brothers safely. Jesse's concern is fraternal welfare, not military intelligence.</p>",
        "19": "<p>The narrative locates Jesse's sons and 'all the men of Israel' in the Valley of Elah 'fighting (<em>nilḥāmîm</em>) the Philistines.' The participle <em>nilḥāmîm</em> is technically a stalemate — they are 'engaged in battle' without resolution. The passive standoff (armies drawn up but no engagement, v21) is where David arrives. The narrator's vocabulary holds two realities: formally there is a war, practically there is a 40-day paralysis.</p>",
        "20": "<p><em>wayyaškēm dāwid babbōqer wayyaʿazeḇ ʾeṯ-haṣṣōʾn ʿal yad šômēr</em> — David 'rose early in the morning and left the flock with a keeper.' Early rising (<em>wayyaškēm</em>) is the mark of diligence throughout the Samuel narrative; leaving the sheep properly attended rather than abandoned shows pastoral responsibility. His arrival at the camp happens to coincide with the battle array drawing up (v21) — the narrator frames the coincidence as providential.</p>",
        "21": "<p><em>wayyaʿarəḵû yiśrāʾēl ûpəlištîm maʿarāḵāh liḳrāṯ maʿarāḵāh</em> — 'Israel and the Philistines drew up battle formation facing each other.' The repetition of <em>maʿarāḵāh</em> ('battle formation, array, line') frames the scene as pure standoff: two battle lines facing each other with no one willing to move. David arrives precisely at the moment of maximum tension and minimum action — when the impasse is most visible and most humiliating.</p>",
        "22": "<p><em>wayyaʿazeḇ dāwid ʾeṯ-kēlāyw ʿal yad šômēr hakkēlîm</em> — 'David left his gear with the keeper of equipment.' The transition from errand-boy to soldier is marked by this administrative detail: David formally checks his supplies with the supply officer before running to the battle line to greet his brothers. The mundane logistics grounds the heroic narrative.</p>",
        "23": "<p>Goliath's appearance and repetition of his challenge (<em>kaddəḇārîm hāʾēlleh</em>, 'those same words') is the narrative trigger. David hears the challenge for the first time at the same moment Goliath delivers it; the repetition for the reader (hearing it the second time) is David's first encounter. His response will be immediate and theologically formed — unlike the forty-day paralysis of the army.</p>",
        "24": "<p><em>wayyānusû mippānāyw wayyirəʾû məʾōḏ</em> — 'they fled from before him and were very afraid.' The verb <em>nûs</em> (to flee, to run away in fear) describes actual retreat from Goliath's advance, not merely standing their ground in fear. This amplifies the impasse: Goliath can actually advance and make Israel run, yet the formal battle has not begun. The daily intimidation has become a rehearsal of defeat.</p>",
        "25": "<p><em>wəhāyāh hāʾîš ʾăšer yakkennû yaʿăśernû hammelek ʿāšer gādôl</em> — 'the king will enrich the man who kills him greatly.' The reward structure — wealth (<em>ʿāšer</em>), the king's daughter, and freedom for his father's house from tax/tribute — is the ANE hero's reward. The detail of freedom from <em>ḥopšî</em> ('freed household,' possibly exemption from corvée or tribute) adds legal specificity. David's question about this reward in v26 shows he is listening to the political economy, not just the military challenge.</p>",
        "27": "<p>The men repeat the reward terms to David: <em>kazzeh yaʿăśeh lāʾîš ʾăšer yakkennû</em> ('this is what will be done for the man who kills him'). The passive construction ('will be done') implies official royal promise; David's inquiry about it in v26 and its repetition here establishes the formal covenantal framework of the reward before David acts. He is not acting from naivety but from full knowledge of the terms.</p>",
        "28": "<p><em>wayyiḥar ʾap-ʾĕlîāḇ bədāwid</em> — 'Eliab's anger burned against David.' <em>ḥārāh ʾap</em> (lit. 'the nose burned') is the standard Hebrew idiom for fierce anger. Eliab's accusation — <em>pəḥazûṯ libbəkā</em> ('the presumption/insolence of your heart') — is exactly the false reading: the reader knows David's heart has been examined by YHWH (16:7) and found worthy. The eldest brother's dismissal is the final repetition of the 16:7 theme — human sight judges wrongly.</p>",
        "29": "<p><em>māh ʿāśîṯî ʿattāh halôʾ dāḇār hûʾ</em> — 'What have I done now? Is it not just talk/a word?' David's response is understated and rhetorical. <em>dāḇār</em> here means a matter worth inquiring about; the question deflects Eliab's attack without engaging it. The brevity is telling: David doesn't defend himself but moves on (v30). The contrast with Eliab's heated accusation underlines David's equanimity.</p>",
        "30": "<p><em>wayyissōḇ mēʾeṣlô ʾel-mul ʾaḥēr</em> — 'he turned away from him to another.' The verb <em>sāḇaḇ</em> (to turn, go around) is physical: David simply walks away from Eliab to ask someone else. The same question produces the same answer; the repetition confirms the reward is publicly known. David's persistence is not stubbornness but methodical information-gathering before action.</p>",
        "31": "<p><em>wayiggāḏû liḵənê šāʾûl</em> — 'what David had said was reported to Saul.' The passive report (<em>wayyaggēḏ</em>, Hiphil, 'was told') shifts the narrative momentum: David's words have now reached the king. Saul's summons (<em>wayyišlaḥ lô</em>, 'he sent for him') sets up the confrontation that will expose Saul's paralysis and provide the opportunity for David's intervention. The passive construction distances David from any self-promotion.</p>",
        "32": "<p><em>ʾal-yippōl lēḇ-ʾādām ʿālāyw</em> — 'let no man's heart fall/fail because of him.' <em>nāpal lēḇ</em> ('heart falls') is the idiom for loss of courage; David is directly addressing the condition described in v11 (<em>ḥāṯaṯ</em>). His self-identification as 'your servant' (<em>ʿaḇdəḵā</em>) is the appropriate court register; his offer to fight the Philistine frames the action as royal service, not personal glory.</p>",
        "33": "<p><em>lōʾ ṯûḵal lāleḵeṯ</em> — 'you are not able to go.' Saul's objection — <em>nəʿar ʾattāh</em> ('you are a young man/boy') and Goliath is a warrior since his youth — names the obvious disproportion. The term <em>nəʿar</em> (youth, boy, servant) can mean anything from infant to military aide; here it emphasises inexperience. Saul's reason is accurate from a purely human perspective; David's response (vv34–37) will reframe the evidence base.</p>",
        "34": "<p><em>ḥōrēh ʾet-ṣōʾn ʾāḇîw</em> — 'tending his father's flock.' David begins his argument with pastoral biography, not military credentials. The encounter with lion and bear (<em>ʾaryēh wəhaḏḏōḇ</em>) establishes a track record of individual combat against superior force — precisely the scenario Goliath presents. The key word is <em>wəhiṣṣaḷtî</em> (Hiphil of <em>nāṣal</em>, 'I rescued'), which David will use again of YHWH in v37.</p>",
        "35": "<p><em>wəhiḵîṯîhû wəhiṣṣaḷtî miqqî</em> — 'I struck it and rescued [the lamb] from its mouth.' The verbs (<em>nākāh</em>, to strike; <em>nāṣal</em>, to rescue) form David's combat vocabulary: he attacks the predator and recovers what was taken. <em>ûḇəqûmô ʿālay wəheḥezaqtî bize<sup>ʿ</sup>qānô</em> ('when it rose against me, I seized it by its beard') describes hand-to-hand wrestling with a lion — the beard of a lion is not a natural fighting target but demonstrates extreme close-range mastery.</p>",
        "36": "<p><em>wəhāyāh hapaləšṯî hāʿārēl hazzeh kəʾaḥaḏ mēhem</em> — 'this uncircumcised Philistine will be like one of them.' David's use of <em>ʿārēl</em> ('uncircumcised') to describe Goliath reframes the combat in covenant terms: circumcision is the sign of the covenant community (Gen 17:11); an uncircumcised man is outside the covenant, therefore outside YHWH's protection. The same word recurs in v26 — David uses it consistently, not as an insult but as a theological categorisation.</p>",
        "37": "<p><em>yhwh ʾăšer hiṣṣilani</em> — 'YHWH who rescued me.' David's conclusion draws the explicit theological inference from his biographical evidence: the rescuing agent in the lion-bear encounters was YHWH, not his own skill. <em>yaṣṣilēnî miqqāṯ hapəlištî hazzeh</em> — 'he will rescue me from the hand of this Philistine.' The same verb (<em>nāṣal</em>) links past pastoral rescue to anticipated military rescue; Saul's response ('Go! YHWH be with you') is a blessing that implies his acceptance of David's theological case.</p>",
        "38": "<p><em>wayyalbiš šāʾûl ʾeṯ-dāwid maḏ·dāyw</em> — 'Saul dressed David in his own military garments.' The attempt to armour David in Saul's equipment is symbolically charged: Saul is trying to make David a smaller version of himself, a warrior equipped in the same military framework that has failed. <em>qôḇaʿ nəḥōšeṯ ʿal-rōʾšô</em> ('a bronze helmet on his head') echoes Goliath's armour description (v5) — David is being made into a miniature Goliath.</p>",
        "39": "<p><em>waylōʾ yāḵōl lahalōḵ kî lōʾ nissāh</em> — 'he could not walk, for he had not tested them.' The verb <em>nāsāh</em> (to test, try, prove) is the same root used for YHWH testing Abraham (Gen 22:1) and Israel's wilderness testing. David had not been tested in this military framework — it is not his. His refusal of the armour and return to his shepherd's staff and sling is the rejection of institutional warfare in favour of the only combat mode he has actually proved.</p>",
        "40": "<p><em>wayyiqkāḥ maqqəlô bəyāḏô wayyiḇḥar-lô ḥămîššāh ʾaḇnê-ḥālaqqôṯ min-hannaḥal</em> — 'five smooth stones from the brook.' The detail of five stones (for one shot) has generated much comment; the LXX reads the same. The practical reason is probably the insurance of multiple attempts; the theological point is that one was sufficient (v49). The shepherd's pouch (<em>yalqûṭ hārōʿîm</em>) and sling (<em>qela<sup>ʿ</sup></em>) are tools of his real vocation — the ones YHWH has already validated in the field.</p>",
        "41": "<p><em>wōlēḵ ûmaggēn lōʾ lippānāyw</em> — Goliath coming forward 'with his shield-bearer walking before him.' The shield-bearer's function is battlefield protection from missiles — exactly what David intends to use. The shield-bearer walks <em>lippānāyw</em> ('before him'), unwittingly positioning himself to screen Goliath from the front while David approaches. The sling projectile from a distance would not be screened by a man-held shield in any case.</p>",
        "42": "<p><em>wayyibbet happəlištî wayyirʾeh ʾeṯ-dāwid wayyibzēhû</em> — 'looked... and despised him.' The verb <em>bāzāh</em> (to despise, hold in contempt) is significant: Goliath's evaluation of David follows the same logic Eliab used — looking at outward appearance. <em>naʿar</em> ('youth'), <em>ʾaḏmōnî</em> ('ruddy'), <em>yəpēh marʾeh</em> ('handsome') are the visible markers of inexperience. YHWH had looked at the same outward description in 16:12 and chosen differently.</p>",
        "43": "<p><em>hakeleḇ ʾānōḵî kî-ʾattāh bāʾ ʾēlay bammaqqəlôṯ</em> — 'Am I a dog, that you come at me with sticks?' The dog-insult is classic ANE combat rhetoric; a <em>keleḇ</em> ('dog') is a contemptible, scavenging animal. Goliath reads the shepherd's staff (<em>maqqēl</em>) as a stick weapon appropriate for a dog-fight, not honourable combat. He curses David 'by his gods' (<em>ʾĕlōhāyw</em>) — invoking Philistine divine authority. The curse by Philistine gods will be answered by YHWH's name (v45).</p>",
        "44": "<p><em>ləḵāh ʾēlay wəʾetənāh ʾeṯ-bəśārəḵā</em> — 'come to me, and I will give your flesh.' Goliath's counter-threat is the mirror of the battlefield consecration formula: the loser's flesh is given to scavenging birds and beasts (<em>ʿôp haššāmayim ûlḇehemōṯ haśśāḏeh</em>). David will use the same language about Goliath and the Philistine army in v46 — the verbal duel matches the physical one, with David turning Goliath's threat back on him.</p>",
        "46": "<p><em>wənāṯattî ʾeṯ-pigrê maḥănēh pəlištîm hayyôm hazzeh</em> — 'I will give the corpses of the Philistine camp this day.' David's proclamation expands Goliath's individual-combat threat into a battle declaration: the entire army will fall. The purpose clause — <em>wəyēḏəʿû kol-hāʾāreṣ kî yēš ʾĕlōhîm ləyiśrāʾēl</em> ('that all the earth may know that there is a God in Israel') — gives the battle cosmic-apologetic significance. Victory will be theological demonstration, not military achievement.</p>",
        "48": "<p><em>wayyāqom dāwid wayyāroṣ hammaʿarāḵāh liḳrāṯ happəlištî</em> — 'David ran quickly toward the battle line to meet the Philistine.' The verb <em>rûṣ</em> (to run) is notable: David initiates the movement, running toward Goliath rather than waiting. This is the opposite of Israel's reaction in v24 (<em>nûs</em>, to flee). The contrast in verbs of movement — flee vs. run toward — is the chapter's climactic physical action before the sling-shot.</p>",
        "50": "<p><em>wayyeḥezaq dāwid min-happəlištî baqqelaʿ ûḇāʾeḇen</em> — 'David prevailed over the Philistine with sling and stone.' The narrator's summary deliberately notes that David 'struck the Philistine and killed him, and there was no sword in David's hand.' The absence of a sword is the point of the whole sequence: conventional weaponry failed; YHWH's intervention through the weakest instrument succeeded. The sword David uses in v51 is Goliath's own.</p>",
        "52": "<p><em>wayyāqumû ʾanšê yiśrāʾēl wîhûḏāh wayyārîʿû</em> — 'the men of Israel and Judah rose up with a shout.' The explicit distinction 'Israel and Judah' (<em>yiśrāʾēl wîhûḏāh</em>) is unusual at this period and may reflect the narrator's knowledge of the later division, or a genuine sense of the tribal tension that will surface in Saul's reign. The pursuit from the valley to Gath and Ekron traces the route back into Philistine heartland.</p>",
        "53": "<p><em>wayyāšuḇû ḇənê yiśrāʾēl middālēq ʾaḥărê pəlištîm</em> — 'returned from pursuing the Philistines.' The plundering of the Philistine camp (<em>wayyāḇōzzû ʾeṯ-maḥănêhem</em>) follows the pattern of holy-war aftermath; the victor takes the spoil of the fleeing enemy. The military reversal is complete: Israel, paralysed for forty days, now pursues the Philistines to their own cities.</p>",
        "54": "<p><em>wayyiqaḥ dāwid ʾeṯ-rōʾš happəlištî wayyəḇîʾēhû yərûšālaim</em> — 'David took the Philistine's head and brought it to Jerusalem.' Jerusalem at this time was still Jebusite (cf. v11's note that it was not Israelite); the placement of Goliath's head there anticipates David's future conquest of the city. The armour is deposited in David's own tent (<em>ʾōhălô</em>), not a royal treasury — David is still a private person at this point.</p>",
        "55": "<p><em>wayōʾmer ʾel-ʾaḇnēr śar haṣṣāḇāʾ ben-mî-zeh hannāʿar</em> — 'Whose son is this young man?' Saul's apparent failure to recognise David (cf. 16:14–23) has generated extensive scholarly discussion. The most plausible readings are: (a) the narrative derives from independent traditions; (b) Saul genuinely does not know David's lineage (family name), though he knows the person; (c) the question is formulaic for establishing David's family claim to the king's daughter and tax exemption promised in v25.</p>",
        "56": "<p><em>biqqəšû ʾattāh ben-mî-zeh hāʿālem</em> — 'find out whose son this young man is.' <em>ʿālem</em> is a hapax in this form; related to <em>ʿelem</em> (young man of fighting age, cf. 20:22); the MKT 'young man' is apt. The inquiry is delegated to Abner and then resolved by David's own identification (v58). The genealogical question matters legally: the promised rewards require knowing the family lineage.</p>",
        "57": "<p><em>wayyiqkāḥ ʾōṯô ʾaḇnēr wayyəḇîʾēhû lippənê šāʾûl ûrōʾš happəlištî bəyāḏô</em> — 'Abner brought him before Saul with the Philistine's head still in his hand.' The detail of David holding Goliath's head during his interview with the king is a powerful image of accomplished fact: the promise has been fulfilled, the evidence is literal and immediate. The scene closes the combat narrative and opens the court narrative.</p>",
        "58": "<p><em>ʾanōḵî ben-ʿaḇdəḵā yišay bêṯ hallaḥmî</em> — 'I am the son of your servant Jesse the Bethlehemite.' David's self-identification uses the deferential 'your servant' (<em>ʿaḇdəḵā</em>) for his father, placing himself within the household of a royal servant. The patronymic 'son of Jesse' (<em>ben-yiśay</em>) becomes David's standard identification throughout Samuel and will carry prophetic weight in later passages (cf. Isa 11:1, the 'shoot from the stump of Jesse').</p>"
    },
    "18": {
        "2": "<p><em>lōʾ nəṯānô lāšûḇ bêṯ ʾāḇîw</em> — 'he did not let him return to his father's house.' Saul's retention of David after the battle formalises the transition hinted at in 16:21–22. The verb <em>nāṯan</em> (to give, allow) in the negative implies royal fiat: David is now a court permanent rather than an occasional visitor. This new status simultaneously elevates David and removes him from his father's protection, setting up the later scenes of vulnerability.</p>",
        "4": "<p><em>wayyiṯpašəṭ yônāṯān ʾeṯ-hamməʿîl ʾăšer ʿālāyw wayyiṯtənēhû lədāwid</em> — 'Jonathan stripped off the robe he was wearing and gave it to David.' The gift of the crown prince's robe (<em>məʿîl</em>) to David is symbolically loaded: the <em>məʿîl</em> is a garment of royal status (cf. 1 Sam 15:27; 24:5, 11, where it marks Saul's kingship). Jonathan's voluntary divestiture anticipates the transfer of the kingdom and is a de facto act of covenant abdication: 'your kingship will be established and I will be second to you' (23:17).</p>",
        "6": "<p><em>wattēṣeʾnāh hanaššîm mikōl ʿārê yiśrāʾēl lāšîr wəhamməḥōlōṯ</em> — 'women came out from all the towns of Israel to sing and to dance.' The women's victory celebration with tambourines (<em>tuppîm</em>), singing, and three-stringed instruments (<em>šālîšîm</em>) follows the Miriam-pattern of Exodus 15 — the women lead the victory song after the decisive battle. The public, communal nature of the celebration makes Saul's jealousy over the song-content all the more politically significant.</p>",
        "7": "<p><em>hikkāh šāʾûl ʾăḷāpāyw wədāwid bərəḇābotāyw</em> — 'Saul has struck down his thousands, but David his ten-thousands.' The antiphonal couplet uses the standard Hebrew poetic number escalation: <em>ʾălāpîm</em> (thousands) vs. <em>rəḇābôṯ</em> (ten-thousands). In victory songs this is a device of comparative praise, not arithmetic; the women are singing in Saul's honour of the whole campaign. But Saul will read it as a zero-sum comparison (v8).</p>",
        "8": "<p><em>wayyiḥar ləšāʾûl məʾōḏ wayyēraʿ bəʿênāyw haddāḇār hazzeh</em> — 'very angry... displeased him greatly' (lit. 'it was evil in his eyes'). <em>rāʿ bəʿênāyw</em> is the technical formula for moral and political displeasure (cf. 2 Sam 11:27, where YHWH uses the same formula for David's sin). Saul's self-comparison — 'only the kingdom is left for him' (<em>hāmalûḵāh ʿôḏ-lô</em>) — is theologically ironic: this is precisely what Samuel has prophesied (13:14; 15:28). Saul's fear is accurate.</p>",
        "9": "<p><em>wayyəhî šāʾûl ʿôyen ʾeṯ-dāwid</em> — 'Saul kept watching David with suspicion/an evil eye.' The phrase <em>ʿôyen ʿayin</em> (lit. 'eye-ing with the eye') implies hostile surveillance; some translations render 'eyed him with jealousy.' The continuous participle marks this as an ongoing attitude that will define the rest of Saul's relationship with David. What begins as jealousy (v8) becomes structural enmity (v29) becomes active murderous intent (19:1).</p>",
        "10": "<p><em>wattislaḥ rûaḥ-ʾĕlōhîm rāʿāh ʾel-šāʾûl</em> — 'an evil spirit from God rushed upon Saul.' The formulation <em>rûaḥ-ʾĕlōhîm rāʿāh</em> ('evil spirit from/of God') repeats the language of 16:14–15 and raises the same theological question: in what sense does YHWH send the evil spirit? The standard reading is that YHWH permits a distressing spirit as part of the judicial abandonment of Saul after his rejection (15:26–28); the spirit is called 'from God' because it operates within YHWH's sovereign governance.</p>",
        "11": "<p><em>wayyāṭel šāʾûl ʾeṯ-haḥănîṯ</em> — 'Saul hurled the spear.' The verb <em>ṭûl</em> (to cast, hurl) here is used for the first of three spear-throwing incidents in Samuel (18:11; 19:10; 20:33). The spear (<em>ḥănîṯ</em>) was a royal symbol — carried by Saul as a sceptre-like weapon (1 Sam 22:6; 26:7). Throwing it at David transfers the symbol from dominion to violence; <em>wayyissōḇ dāwid mippānāyw paaʿmayim</em> ('David eluded him twice') — the double escape foreshadows David's repeated deliverance.</p>",
        "13": "<p><em>wayyāsirēhû šāʾûl mēʿimmô wayyāśem ʾōṯô lô śar-ʾalep</em> — 'Saul removed him from his personal service and made him a commander of a thousand.' The removal from <em>ʿimmô</em> ('with him,' personal attendance) to field command over a <em>śar-ʾalep</em> ('commander of a thousand,' a standard military unit) is a combination of lateral promotion and distancing. David is simultaneously honoured and removed from the potentially dangerous proximity of the court. The plan backfires: <em>wayyēṣēʾ wayyābōʾ</em> ('he went out and came in') and the people's love for him grows (v16).</p>",
        "14": "<p><em>wayhî dāwid maśkîl bəḵōl dərāḵāyw</em> — 'David prospered/acted wisely in all his ways.' <em>śāḵal</em> (Hiphil: to be wise, prudent, to prosper) is a key term in the wisdom tradition; its use here ties David's success to divinely-given wisdom rather than military prowess alone. The causal clause <em>wayhwh ʿimmô</em> ('and YHWH was with him') repeats the theological explanation of David's success that will recur throughout Samuel (cf. 2 Sam 5:10; 7:3).</p>",
        "15": "<p><em>wayyirʾ šāʾûl ʾăšer hûʾ maśkîl məʾōḏ</em> — 'Saul saw that he was very successful/wise.' Saul's fear (<em>yārēʾ</em>) is now directed at David's demonstrated competence, not just the women's song. The verb <em>śāḵal</em> recurs from v14: what David is (<em>maśkîl</em>) is exactly what Saul fears. Fear and awe of YHWH's chosen one is a recurring motif; Saul's fear of David is a perverse form of recognising the presence of YHWH with David.</p>",
        "16": "<p><em>wəḵol-yiśrāʾēl wîhûḏāh ʾōhēḇ ʾeṯ-dāwid</em> — 'all Israel and Judah loved David.' The subject 'all Israel and Judah' reappears (cf. v5, 17:52) as the narrative marker of David's national support cutting across the later tribal divide. <em>yōṣēʾ wāḇāʾ lipnêhem</em> ('going out and coming in before them') is the idiom for military leadership (Num 27:17; Deut 31:2); the people love him because he leads from the front. This is precisely what Saul was supposed to do (1 Sam 8:20) and cannot.</p>",
        "17": "<p><em>hinnēh bittî hagəḏôlāh mēraḇ</em> — 'here is my eldest daughter Merab.' Saul's offer of Merab fulfils the reward promised in 17:25. <em>raq heyēh-lî libben-ḥayil</em> ('only be a courageous man for me') conditions the marriage on continued military service, effectively using Merab as an incentive to keep David fighting — and potentially dying — against the Philistines. The phrase 'let the hand of the Philistines be against him' (v17b) makes Saul's motive explicit.</p>",
        "18": "<p><em>mî ʾānōḵî ûmî ḥayyay</em> — 'who am I, and what is my life?' David's self-deprecation before Saul is the correct ANE vassal speech — humility before the king. <em>mišpaḥaṯ ʾāḇî bəyiśrāʾēl</em> ('my father's family in Israel') — the question about his clan's status suggests David recognises that his family is not noble enough to provide a queen. The response delays the marriage while maintaining correct protocol; Saul uses the delay to give Merab elsewhere.</p>",
        "19": "<p><em>wattinnaṯēn mēraḇ baṯ-šāʾûl ləʿadrîʾēl hamməḥōlaṯî</em> — 'Merab was given to Adriel the Meholathite.' The passive construction (<em>tinnaṯēn</em>) removes Saul from grammatical agency — suggesting either that Saul quietly arranged the betrothal before David could claim Merab, or that it happened without dramatic confrontation. Adriel from Abel Meholah (possibly Tell Abu Sifri in the Jordan valley) is otherwise unknown; the marriage is purely strategic for Saul, disposing of the promised bride without honouring the promise.</p>",
        "20": "<p><em>wattēʾahaḇ miḵal baṯ-šāʾûl ʾeṯ-dāwid wayyaggidû ləšāʾûl wayyiyšar haddāḇār bəʿênāyw</em> — 'Michal... loved David and Saul was pleased.' The note that Michal loves David is the only OT passage where a woman's love for her husband is explicitly stated as initiating the marriage relationship. Saul's pleasure is sinister: he sees an opportunity to use Michal as a snare (<em>môqēš</em>, v21) since David's love for Michal will make him take greater risks.</p>",
        "21": "<p><em>ʾettənennāh lô wətihy-lô lāmôqēš</em> — 'I will give her to him so that she may be a snare to him.' <em>mōqēš</em> (trap, snare) is the same word used in covenant warnings against intermarriage with Canaanites (Ex 23:33; 34:12). Saul is planning to use Israel's marriage institution as a weapon against YHWH's chosen man. The verb <em>tihy-lô lāmôqēš</em> ('she will be a snare to him') is a bitter inversion of Ruth 4:11, where a good wife is a blessing.</p>",
        "22": "<p><em>ʾitdabəru ʾel-dāwid bassēṯer</em> — 'speak to David privately.' Saul instructs his servants to create false intimacy — telling David that Saul is 'pleased with him' and that 'his servants love him' — to pressure David into pursuing Michal. The word <em>bassēṯer</em> ('in secret/privately') signals that the whole transaction operates through deception. David's eventual response (v23) shows he sees through the social pressure without being deceived about his own status.</p>",
        "23": "<p><em>haniqallāh bəʿênêḵem hiṯḥatten bammelek</em> — 'Does it seem a small thing to you to become the king's son-in-law?' David's response again uses the expected humility formula but also signals awareness of the political significance of the offer. <em>ʾanōḵî ʾîš-rāʾš ûniqləh</em> ('I am a poor and lightly-esteemed man') — <em>rāʾš</em> (poor, without resources) and <em>niqləh</em> (of light weight, held in low regard) are the social vocabulary of outsider status. David's stated self-assessment protects him from appearing to seek the throne.</p>",
        "24": "<p><em>wayyaggidû ləšāʾûl ʾēmōr kaddəḇārîm hāʾēlleh dibber dāwid</em> — 'they reported back to Saul: this is what David said.' The servants' function as intermediaries creates a layer of mediation between Saul's manipulation and David's response; David never speaks directly to Saul in these marriage negotiations. The report structure allows Saul to proceed to his next manoeuvre (v25) without being directly refused.</p>",
        "25": "<p><em>ʾên ḥēpeṣ lammelek bemōhar kî bimêʾāh ʿarlôṯ pəlištîm</em> — 'the king desires no dowry (<em>mōhar</em>) except a hundred foreskins of the Philistines.' The <em>mōhar</em> was the standard bride-price paid by the groom's family; Saul replaces it with a military trophies requirement. The mutilation of slain enemies (taking their foreskins or hands as body-count proof) was documented in ANE warfare; 2 Sam 3:14 preserves the completed transaction as '200 foreskins.' Saul's explicit motive — 'as vengeance on the king's enemies' — frames the request as holy war service while actually intending David's death.</p>",
        "26": "<p><em>wayyîšar haddāḇār bəʿênê dāwid liḥtiḥatten bammelek</em> — 'it pleased David to become the king's son-in-law.' The parallel phrasing to Saul's pleasure at Michal's love (v20, <em>wayyiyšar haddāḇār bəʿênāyw</em>) is deliberate irony: both king and subject are 'pleased,' but for entirely different reasons. David accepts the terms; the narrator notes that the time set was not yet expired — he will move before Saul expects.</p>",
        "27": "<p><em>wayyāqom dāwid wayyēlek hûʾ wəʾanāšāyw wayyakku ḇappəlištîm māʾtayim ʾîš</em> — 'David and his men struck down two hundred Philistines.' David delivers double the required number (200 vs. 100), and the narrator records that he presented the foreskins in full count to the king. The doubling is not explained — perhaps military circumstance — but functions narratively as excess zeal that confounds Saul's expectation of David's death. Saul is forced to give Michal as promised, and the marriage is formalised.</p>",
        "28": "<p><em>wayyarʾ šāʾûl wayēḏaʿ kî yhwh ʿim-dāwid</em> — 'Saul saw and knew that YHWH was with David.' Saul's knowledge is explicit recognition of the theological reality: the reason David cannot be killed is not his own skill but divine protection. <em>ûmiḵal baṯ-šāʾûl ʾăhēḇāṯhû</em> ('and Michal his daughter loved him') repeats Michal's love as political fact — the tool Saul intended as a snare has become evidence of David's irresistible favour.</p>",
        "29": "<p><em>wayyōsep šāʾûl lîrōʾ mippənê dāwid ʿôḏ wayhî šāʾûl ʾōyēḇ ʾeṯ-dāwid kol-hayyāmîm</em> — 'Saul became even more afraid of David, and was David's enemy all his days.' The progression is complete: suspicion (v9) → fear (v12) → active enmity (<em>ʾōyēḇ</em>, enemy) for 'all his days.' <em>kol-hayyāmîm</em> ('all the days') is a permanent narrative verdict; the relationship between Saul and David is now defined as structural enmity, not episodic conflict.</p>",
        "30": "<p><em>wayyaśkēl dāwid mikkōl ʿaḇdê šāʾûl wayyiqar šəmô məʾōḏ</em> — 'David performed more successfully than all Saul's servants, and his name was highly honoured.' The chapter ends on the twin notes that characterise David throughout 1 Samuel: <em>śāḵal</em> (wise/successful — repeated from vv5, 14, 15) and <em>yāqar šēm</em> ('his name was precious/highly esteemed'). Both terms are gifts of YHWH's presence; the chapter that began with Goliath's taunt ends with David's name held in high honour.</p>"
    }
}

def main():
    existing = load_comm('original', '1samuel')
    merge_comm(existing, SAMUEL)
    save_comm('original', '1samuel', existing)
    print('1 Samuel 17-18 original fill: 78 verses written.')

if __name__ == '__main__':
    main()
